class Solution:
    def accountsMerge(self, accounts):
        from collections import defaultdict
        graph = defaultdict(set)
        email_name = {}
        for acc in accounts:
            name = acc[0]
            first = acc[1]
            for e in acc[1:]:
                email_name[e] = name
                graph[first].add(e)
                graph[e].add(first)
        seen = set()
        result = []
        for e in graph:
            if e in seen:
                continue
            stack = [e]
            comp = []
            seen.add(e)
            while stack:
                cur = stack.pop()
                comp.append(cur)
                for nb in graph[cur]:
                    if nb not in seen:
                        seen.add(nb)
                        stack.append(nb)
            result.append([email_name[e]] + sorted(comp))
        return result

